// Performance best practices for large-scale queries

// FAST: filter by type first, then access properties
Resources
| where type =~ 'microsoft.compute/virtualmachines'          // index lookup
| where tostring(properties.hardwareProfile.vmSize) startswith 'Standard_D'
| project name, resourceGroup, subscriptionId

// SLOW: access properties before type filter
// Avoid this — scans every resource in the table:
// Resources
// | where tostring(properties.hardwareProfile.vmSize) startswith 'Standard_D'
// | where type =~ 'microsoft.compute/virtualmachines'

// FAST: project only the columns you need
Resources
| where type =~ 'microsoft.network/networksecuritygroups'
| project name, resourceGroup, location   // narrow result set early

// FAST: use =~ for type comparisons (built-in index)
// SLOW: use tolower(type) == '...' (forces a function on every row)

// FAST: push summarize as early as possible to reduce rows
Resources
| where type =~ 'microsoft.storage/storageaccounts'
| summarize Count = count() by resourceGroup, subscriptionId  // aggregate before join
| where Count > 10

// Use 'top N by column' instead of 'order by + limit' for better optimizer hints
Resources
| where type =~ 'microsoft.compute/disks'
| extend diskSizeGB = toint(properties.diskSizeGB)
| top 50 by diskSizeGB desc
| project name, resourceGroup, diskSizeGB
